#include <stdio.h>
#include <string.h>
int main(void) {
    char buf[512];
    memset(buf, 0, sizeof(buf));
    FILE *f = fmemopen(buf, sizeof(buf), "w");
    if (!f) { printf("fmemopen failed\n"); return 1; }
    fprintf(f, "nom,age,role\n");
    fprintf(f, "Alice,30,admin\n");
    fprintf(f, "Bob,25,user\n");
    fprintf(f, "Carol,35,moderator\n");
    fclose(f);
    printf("%s", buf);
    return 0;
}

