#include <stdio.h>
#include <string.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    char buf[512];
    memset(buf, 0, sizeof(buf));
    FILE *f = fmemopen(buf, sizeof(buf), "w"); // ★ FILE* depuis buffer RAM
    if (!f) { printf("fmemopen failed\n"); return 1; }
    fprintf(f, "nom,age,role\n");      // ★ fprintf = comme printf mais vers FILE*
    fprintf(f, "Alice,30,admin\n");
    fprintf(f, "Bob,25,user\n");
    fprintf(f, "Carol,35,moderator\n");
    fclose(f); // ★ flush obligatoire avant de lire buf
    printf("%s", buf);
    return 0;
}

